import { type Request, type Response, type NextFunction } from 'express';
  import { EventEmitter } from 'events';

  // Track whether frontend is fully loaded
  let frontendReady = false;

  // Event emitter used to notify SSE clients when the app becomes ready
  const readinessEmitter = new EventEmitter();
  readinessEmitter.setMaxListeners(200);

  export function setFrontendReady(ready: boolean) {
    frontendReady = ready;
    if (ready) {
      readinessEmitter.emit('ready');
    }
  }

  export function isFrontendReady(): boolean {
    return frontendReady;
  }

  /**
   * Inline base64 Koveo logo (JPEG) so the maintenance page has no external asset deps.
   */
  const KOVEO_LOGO_B64 = '';

  /**
   * Detect the preferred language from an Accept-Language header.
   * Returns 'fr' or 'en'. Defaults to 'fr' (Quebec platform).
   */
  function detectLang(acceptLanguage: string | undefined): 'fr' | 'en' {
    if (!acceptLanguage) return 'fr';
    const firstTag = acceptLanguage.split(',')[0]?.split(';')[0]?.trim().toLowerCase() ?? '';
    if (firstTag.startsWith('en')) return 'en';
    return 'fr';
  }

  /**
   * Render the self-contained branded maintenance page.
   * No external JS/CSS/image dependencies — everything is inline.
   */
  export function renderMaintenancePage(acceptLanguage?: string): string {
    const primaryLang = detectLang(acceptLanguage);
    const etaRaw = process.env.MAINTENANCE_ETA ?? '';
    const statusUrl = process.env.STATUS_PAGE_URL ?? '/status';

    const etaBlock = etaRaw
      ? `<p class="eta"><span class="label-fr">Retour estimé&nbsp;: </span><span class="label-en">Estimated return&nbsp;: </span><strong>${etaRaw}</strong></p>`
      : '';

    return `<!DOCTYPE html>
  <html lang="${primaryLang}">
  <head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Koveo Gestion — Maintenance</title>
    <style>
      *, *::before, *::after { box-sizing: border-box; }
      body {
        margin: 0;
        min-height: 100vh;
        display: flex;
        flex-direction: column;
        align-items: center;
        justify-content: center;
        background: linear-gradient(135deg, #0f172a 0%, #1e293b 100%);
        font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
        color: #f1f5f9;
        padding: 2rem 1rem;
      }
      .card {
        background: rgba(255,255,255,0.06);
        border: 1px solid rgba(255,255,255,0.12);
        border-radius: 16px;
        padding: 3rem 2.5rem;
        max-width: 520px;
        width: 100%;
        text-align: center;
        box-shadow: 0 24px 48px rgba(0,0,0,0.4);
      }
      .logo-wrap { margin-bottom: 2rem; }
      .logo-wrap img {
        height: 48px;
        width: auto;
        object-fit: contain;
        border-radius: 6px;
      }
      .icon {
        width: 56px;
        height: 56px;
        border-radius: 50%;
        background: rgba(59,130,246,0.15);
        display: flex;
        align-items: center;
        justify-content: center;
        margin: 0 auto 1.5rem;
      }
      .icon svg { width: 28px; height: 28px; stroke: #60a5fa; fill: none; stroke-width: 2; stroke-linecap: round; stroke-linejoin: round; }
      .lang-block { margin-bottom: 1rem; }
      .lang-block + .lang-block { padding-top: 1rem; border-top: 1px solid rgba(255,255,255,0.08); }
      h1 { font-size: 1.4rem; font-weight: 600; margin: 0 0 0.5rem; color: #f8fafc; }
      p { margin: 0 0 0.5rem; color: #94a3b8; font-size: 0.95rem; line-height: 1.6; }
      p:last-child { margin-bottom: 0; }
      .eta { margin-top: 0.4rem; color: #cbd5e1; font-size: 0.9rem; }
      .divider { height: 1px; background: rgba(255,255,255,0.08); margin: 1.5rem 0; }
      .actions { display: flex; flex-direction: column; gap: 0.75rem; align-items: center; margin-top: 1.5rem; }
      .btn-retry {
        display: inline-flex;
        align-items: center;
        gap: 0.5rem;
        background: #3b82f6;
        color: #fff;
        border: none;
        border-radius: 8px;
        padding: 0.65rem 1.4rem;
        font-size: 0.9rem;
        font-weight: 500;
        cursor: pointer;
        transition: background 0.15s;
        text-decoration: none;
      }
      .btn-retry:hover { background: #2563eb; }
      .btn-retry svg { width: 16px; height: 16px; stroke: currentColor; fill: none; stroke-width: 2; stroke-linecap: round; stroke-linejoin: round; }
      .status-link { font-size: 0.82rem; color: #64748b; text-decoration: none; transition: color 0.15s; }
      .status-link:hover { color: #94a3b8; }
      .pulse-dot {
        display: inline-block;
        width: 8px; height: 8px;
        background: #facc15;
        border-radius: 50%;
        margin-right: 6px;
        animation: pulse 1.8s ease-in-out infinite;
      }
      @keyframes pulse {
        0%, 100% { opacity: 1; transform: scale(1); }
        50% { opacity: 0.4; transform: scale(0.7); }
      }
      .status-row { display: flex; align-items: center; justify-content: center; font-size: 0.8rem; color: #64748b; margin-top: 0.5rem; }
      #sse-status { color: #64748b; font-size: 0.78rem; margin-top: 0.4rem; }
    </style>
  </head>
  <body>
    <div class="card">
      <div class="logo-wrap">
        <img src="data:image/jpeg;base64,${KOVEO_LOGO_B64}" alt="Koveo Gestion" />
      </div>

      <div class="icon">
        <svg viewBox="0 0 24 24"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg>
      </div>

      <div class="lang-block">
        <h1>Maintenance en cours</h1>
        <p>L'application est temporairement indisponible pendant la mise à jour du serveur. Elle sera de retour très bientôt.</p>
        ${etaBlock}
      </div>

      <div class="divider"></div>

      <div class="lang-block">
        <h1>Maintenance in progress</h1>
        <p>The application is temporarily unavailable while the server is being updated. It will be back very shortly.</p>
        ${etaBlock}
      </div>

      <div class="divider"></div>

      <div class="actions">
        <div class="status-row">
          <span class="pulse-dot"></span>
          <span id="sse-status">Vérification en cours… / Checking…</span>
        </div>
        <button class="btn-retry" onclick="retryNow()">
          <svg viewBox="0 0 24 24"><polyline points="23 4 23 10 17 10"/><path d="M20.49 15a9 9 0 1 1-2.12-9.36L23 10"/></svg>
          Réessayer&nbsp;/&nbsp;Try again
        </button>
        <a class="status-link" href="${statusUrl}" target="_blank" rel="noopener">
          Voir la page de statut / View status page →
        </a>
      </div>
    </div>

    <script>
      (function () {
        function retryNow() {
          window.location.reload();
        }
        window.retryNow = retryNow;

        var statusEl = document.getElementById('sse-status');

        // Try Server-Sent Events first for a no-flicker auto-redirect
        try {
          var es = new EventSource('/maintenance/events');

          es.addEventListener('ready', function () {
            es.close();
            if (statusEl) statusEl.textContent = 'Prêt! Redirection… / Ready! Redirecting…';
            // Small delay so the user sees the message, then navigate home
            setTimeout(function () { window.location.href = '/'; }, 800);
          });

          es.addEventListener('ping', function () {
            // Keep-alive ping, do nothing
          });

          es.onerror = function () {
            es.close();
            if (statusEl) statusEl.textContent = 'Cliquer pour réessayer / Click to try again';
          };
        } catch (e) {
          // SSE not available — user can click retry
          if (statusEl) statusEl.textContent = 'Cliquer pour réessayer / Click to try again';
        }
      })();
    </script>
  </body>
  </html>`;
  }

  /**
   * SSE handler for /maintenance/events.
   * Emits a "ready" event when the frontend becomes available so the
   * maintenance page can auto-navigate to "/" without a polling reload loop.
   */
  export function createMaintenanceEventsHandler() {
    return (req: Request, res: Response) => {
      res.set({
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        Connection: 'keep-alive',
        'X-Accel-Buffering': 'no',
      });
      res.flushHeaders();

      // If already ready, fire immediately
      if (frontendReady) {
        res.write('event: ready\ndata: {}\n\n');
        res.end();
        return;
      }

      // Keep-alive ping every 15 s so proxies don't close the connection
      const pingInterval = setInterval(() => {
        if (!res.writableEnded) {
          res.write('event: ping\ndata: {}\n\n');
        }
      }, 15000);

      function onReady() {
        clearInterval(pingInterval);
        if (!res.writableEnded) {
          res.write('event: ready\ndata: {}\n\n');
          res.end();
        }
      }

      readinessEmitter.once('ready', onReady);

      req.on('close', () => {
        clearInterval(pingInterval);
        readinessEmitter.removeListener('ready', onReady);
      });
    };
  }

  /**
   * Startup middleware that handles ALL routes during initialization
   * This prevents 503 errors for any route while the server is starting up
   */
  export function createStartupMiddleware() {
    return (req: Request, res: Response, next: NextFunction) => {
      // If frontend is ready, pass through to normal handlers
      if (frontendReady) {
        return next();
      }

      // Check if this is a health check endpoint - always pass through
      // Note: '/' is NOT included here - we want to show loading page for browser visits
      // Platform health checks use user-agent detection below
      const healthPaths = ['/health', '/healthz', '/ready', '/ping', '/status', '/api/health'];
      if (healthPaths.includes(req.path)) {
        return next();
      }

      // Allow the SSE readiness stream and the maintenance route through the startup
      // middleware so they are reachable while the app is not yet ready.
      if (req.path === '/maintenance/events' || req.path === '/maintenance') {
        return next();
      }

      // Check user agent for health check bots
      const userAgent = req.get('User-Agent') || '';
      const isHealthCheckBot =
        userAgent.includes('GoogleHC') ||
        userAgent.includes('Cloud-Run-Health-Check') ||
        userAgent.includes('kube-probe') ||
        userAgent.includes('ELB-HealthChecker') ||
        userAgent.includes('AWS-HealthChecker') ||
        userAgent.includes('Pingdom') ||
        userAgent.includes('StatusCake') ||
        userAgent.includes('deployment-health') ||
        req.headers['x-health-check'] === 'true' ||
        req.headers['x-deployment-check'] === 'true';

      if (isHealthCheckBot) {
        return next();
      }

      // For API requests during startup, return 200 with a "starting" status
      // This prevents frontend error handling from showing errors during startup
      if (req.path.startsWith('/api/')) {
        res.set({
          'Content-Type': 'application/json',
          'Cache-Control': 'no-store, no-cache, must-revalidate',
        });
        return res.status(200).json({
          status: 'starting',
          message: "Le serveur est en cours d'initialisation. Veuillez patienter.",
          retryAfter: 2,
          ready: false
        });
      }

      // Check if this is a static asset request
      const isStaticAsset = req.path.match(/\.(js|css|png|jpg|jpeg|gif|ico|svg|woff|woff2|ttf|eot|json|map)$/);
      
      // For static assets during startup, return 503 with no-store to prevent caching
      if (isStaticAsset) {
        res.set({
          'Cache-Control': 'no-store, no-cache, must-revalidate',
          'Pragma': 'no-cache',
          'Retry-After': '2',
        });
        return res.status(503).end();
      }

      // For all other requests (browser navigation), show the branded maintenance page
      res.set({
        'Content-Type': 'text/html',
        'Cache-Control': 'no-store, no-cache, must-revalidate',
        'Pragma': 'no-cache',
        'Expires': '0',
      });
      return res.status(200).send(renderMaintenancePage(req.get('Accept-Language')));
    };
  }

  /**
   * Ultra-fast health check handler optimized for deployment platforms
   * Responds immediately with minimal processing to prevent timeouts
   */
  export function createFastHealthCheck() {
    return (req: Request, res: Response) => {
      // Set immediate timeout to prevent any hanging
      req.setTimeout(200, () => {
        if (!res.headersSent) {
          res.status(200).json({ status: 'ok', uptime: process.uptime() });
        }
      });

      // Set ultra-fast response headers
      res.set({
        'Cache-Control': 'no-cache, no-store, must-revalidate',
        Connection: 'close',
        'Content-Type': 'application/json',
        'X-Health-Check': 'OK',
        'X-Response-Time': Date.now().toString(),
      });

      // Send immediate response - no async operations
      res.status(200).json({ status: 'ok', uptime: process.uptime() });
    };
  }

  /**
   * Fast JSON health status for monitoring
   */
  export function createStatusCheck() {
    return (req: Request, res: Response) => {
      // Set immediate timeout
      req.setTimeout(200, () => {
        if (!res.headersSent) {
          res.status(200).json({ status: 'ok' });
        }
      });

      // Set headers for fast response
      res.set({
        'Cache-Control': 'no-cache, no-store, must-revalidate',
        Connection: 'close',
        'Content-Type': 'application/json',
      });

      // Send immediate JSON response with minimal data
      res.status(200).json({
        status: 'ok',
        timestamp: Date.now(),
      });
    };
  }

  /**
   * Root endpoint handler that prioritizes health checks
   * Startup logic is now handled by createStartupMiddleware
   */
  export function createRootHandler() {
    return (req: Request, res: Response, next: Function) => {
      // Set ultra-short timeout for health checks
      req.setTimeout(100, () => {
        if (!res.headersSent) {
          res.status(200).send('OK');
        }
      });

      const userAgent = req.get('User-Agent') || '';
      const isHealthCheck =
        userAgent.includes('GoogleHC') ||
        userAgent.includes('Cloud-Run-Health-Check') ||
        userAgent.includes('kube-probe') ||
        userAgent.includes('ELB-HealthChecker') ||
        userAgent.includes('AWS-HealthChecker') ||
        userAgent.includes('Pingdom') ||
        userAgent.includes('StatusCake') ||
        userAgent.includes('deployment-health') ||
        req.headers['x-health-check'] === 'true' ||
        req.query.health === 'true' ||
        req.headers['x-deployment-check'] === 'true' ||
        (userAgent.startsWith('curl') && req.headers['accept'] === '*/*');

      // For deployment platforms and health checks, respond immediately with OK
      if (isHealthCheck) {
        res.set({
          Connection: 'close',
          'Content-Type': 'text/plain',
        });
        res.status(200).send('OK');
        return;
      }

      // For all other requests, pass to next handler (Vite/static files)
      // Startup handling is done by createStartupMiddleware
      return next();
    };
  }
  